import os
import shutil
from datetime import datetime
from flask import Flask, request, jsonify, send_file, abort

app = Flask(__name__)

# Base directory where all user uploads are stored
BASE_UPLOAD_DIR = os.path.abspath(os.path.join(os.path.dirname(__file__), 'uploads'))

# Ensure the base upload directory exists
os.makedirs(BASE_UPLOAD_DIR, exist_ok=True)


def get_user_root(user_id):
    """Get the root directory for a specific user."""
    user_root = os.path.abspath(os.path.join(BASE_UPLOAD_DIR, str(user_id)))
    os.makedirs(user_root, exist_ok=True)
    return user_root


def resolve_safe_path(user_root, relative_path):
    """
    Safely resolve a user-provided relative path to an absolute path
    within the user's root directory. Prevents directory traversal attacks.
    """
    if relative_path is None:
        relative_path = ''

    # Normalize the path to handle '..' and other path components
    normalized = os.path.normpath(relative_path)

    # Join with user root
    full_path = os.path.join(user_root, normalized)

    # Get the absolute path
    full_path = os.path.abspath(full_path)

    # Security check: ensure the resolved path is within the user's root directory
    user_root_abs = os.path.abspath(user_root)
    if not full_path.startswith(user_root_abs + os.sep) and full_path != user_root_abs:
        return None

    return full_path


def get_file_info(file_path, user_root):
    """Get detailed information about a file or directory."""
    stat = os.stat(file_path)
    relative_path = os.path.relpath(file_path, user_root)
    if relative_path == '.':
        relative_path = ''

    info = {
        'name': os.path.basename(file_path) or '/',
        'path': relative_path,
        'is_directory': os.path.isdir(file_path),
        'size_bytes': stat.st_size,
        'created': datetime.fromtimestamp(stat.st_ctime).isoformat(),
        'modified': datetime.fromtimestamp(stat.st_mtime).isoformat(),
        'accessed': datetime.fromtimestamp(stat.st_atime).isoformat(),
    }

    if os.path.isfile(file_path):
        _, ext = os.path.splitext(file_path)
        info['extension'] = ext.lstrip('.')
    elif os.path.isdir(file_path):
        try:
            contents = os.listdir(file_path)
            info['num_items'] = len(contents)
        except PermissionError:
            info['num_items'] = None

    return info


@app.route('/api/files/list', methods=['GET'])
def list_directory():
    """
    List contents of a directory.
    Query params:
        - user_id: the user identifier
        - path: relative path within user's root (default: '')
    """
    user_id = request.args.get('user_id')
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400

    relative_path = request.args.get('path', '')
    user_root = get_user_root(user_id)
    full_path = resolve_safe_path(user_root, relative_path)

    if full_path is None:
        return jsonify({'error': 'Access denied: path is outside your root directory'}), 403

    if not os.path.exists(full_path):
        return jsonify({'error': 'Path not found'}), 404

    if not os.path.isdir(full_path):
        return jsonify({'error': 'Path is not a directory'}), 400

    try:
        entries = []
        for entry_name in sorted(os.listdir(full_path)):
            entry_path = os.path.join(full_path, entry_name)
            entry_info = get_file_info(entry_path, user_root)
            entries.append(entry_info)

        current_relative = os.path.relpath(full_path, user_root)
        if current_relative == '.':
            current_relative = ''

        # Calculate parent path
        parent_path = None
        if current_relative:
            parent = os.path.dirname(current_relative)
            parent_path = parent if parent != current_relative else ''

        return jsonify({
            'current_path': current_relative,
            'parent_path': parent_path,
            'total_items': len(entries),
            'entries': entries
        }), 200

    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403


@app.route('/api/files/info', methods=['GET'])
def file_info():
    """
    Get detailed information about a file or directory.
    Query params:
        - user_id: the user identifier
        - path: relative path to the file/directory
    """
    user_id = request.args.get('user_id')
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400

    relative_path = request.args.get('path', '')
    user_root = get_user_root(user_id)
    full_path = resolve_safe_path(user_root, relative_path)

    if full_path is None:
        return jsonify({'error': 'Access denied: path is outside your root directory'}), 403

    if not os.path.exists(full_path):
        return jsonify({'error': 'Path not found'}), 404

    try:
        info = get_file_info(full_path, user_root)

        # Add additional details for the info endpoint
        if os.path.isdir(full_path):
            # Calculate total size of directory
            total_size = 0
            file_count = 0
            dir_count = 0
            for dirpath, dirnames, filenames in os.walk(full_path):
                dir_count += len(dirnames)
                for f in filenames:
                    fp = os.path.join(dirpath, f)
                    if os.path.isfile(fp):
                        total_size += os.path.getsize(fp)
                        file_count += 1
            info['total_size_bytes'] = total_size
            info['total_files'] = file_count
            info['total_subdirectories'] = dir_count

        # Human-readable size
        size = info.get('total_size_bytes', info['size_bytes'])
        info['size_human'] = _human_readable_size(size)

        return jsonify(info), 200

    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403


@app.route('/api/files/download', methods=['GET'])
def download_file():
    """
    Download a file.
    Query params:
        - user_id: the user identifier
        - path: relative path to the file
    """
    user_id = request.args.get('user_id')
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400

    relative_path = request.args.get('path', '')
    if not relative_path:
        return jsonify({'error': 'path is required'}), 400

    user_root = get_user_root(user_id)
    full_path = resolve_safe_path(user_root, relative_path)

    if full_path is None:
        return jsonify({'error': 'Access denied: path is outside your root directory'}), 403

    if not os.path.exists(full_path):
        return jsonify({'error': 'File not found'}), 404

    if os.path.isdir(full_path):
        return jsonify({'error': 'Cannot download a directory. Use the list endpoint to browse it.'}), 400

    try:
        return send_file(
            full_path,
            as_attachment=True,
            download_name=os.path.basename(full_path)
        )
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403


@app.route('/api/files/upload', methods=['POST'])
def upload_file():
    """
    Upload a file to a specified directory.
    Form data:
        - user_id: the user identifier
        - path: relative directory path where file should be uploaded (default: '')
        - file: the file to upload
    """
    user_id = request.form.get('user_id')
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400

    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400

    relative_path = request.form.get('path', '')
    user_root = get_user_root(user_id)
    target_dir = resolve_safe_path(user_root, relative_path)

    if target_dir is None:
        return jsonify({'error': 'Access denied: path is outside your root directory'}), 403

    # Create directory if it doesn't exist
    os.makedirs(target_dir, exist_ok=True)

    # Sanitize filename
    filename = os.path.basename(file.filename)
    if not filename:
        return jsonify({'error': 'Invalid filename'}), 400

    file_path = os.path.join(target_dir, filename)

    # Verify the final path is still within user root
    file_path_abs = os.path.abspath(file_path)
    if not file_path_abs.startswith(os.path.abspath(user_root) + os.sep):
        return jsonify({'error': 'Access denied'}), 403

    file.save(file_path)

    info = get_file_info(file_path, user_root)
    return jsonify({
        'message': 'File uploaded successfully',
        'file': info
    }), 201


@app.route('/api/files/mkdir', methods=['POST'])
def create_directory():
    """
    Create a new directory.
    JSON body:
        - user_id: the user identifier
        - path: relative path of the directory to create
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body is required'}), 400

    user_id = data.get('user_id')
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400

    relative_path = data.get('path', '')
    if not relative_path:
        return jsonify({'error': 'path is required'}), 400

    user_root = get_user_root(user_id)
    full_path = resolve_safe_path(user_root, relative_path)

    if full_path is None:
        return jsonify({'error': 'Access denied: path is outside your root directory'}), 403

    if os.path.exists(full_path):
        return jsonify({'error': 'Path already exists'}), 409

    try:
        os.makedirs(full_path, exist_ok=False)
        info = get_file_info(full_path, user_root)
        return jsonify({
            'message': 'Directory created successfully',
            'directory': info
        }), 201
    except OSError as e:
        return jsonify({'error': f'Failed to create directory: {str(e)}'}), 500


@app.route('/api/files/delete', methods=['DELETE'])
def delete_file():
    """
    Delete a file or directory.
    Query params:
        - user_id: the user identifier
        - path: relative path to the file/directory to delete
    """
    user_id = request.args.get('user_id')
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400

    relative_path = request.args.get('path', '')
    if not relative_path:
        return jsonify({'error': 'path is required (cannot delete root)'}), 400

    user_root = get_user_root(user_id)
    full_path = resolve_safe_path(user_root, relative_path)

    if full_path is None:
        return jsonify({'error': 'Access denied: path is outside your root directory'}), 403

    # Prevent deleting the user root
    if os.path.abspath(full_path) == os.path.abspath(user_root):
        return jsonify({'error': 'Cannot delete root directory'}), 403

    if not os.path.exists(full_path):
        return jsonify({'error': 'Path not found'}), 404

    try:
        if os.path.isdir(full_path):
            shutil.rmtree(full_path)
        else:
            os.remove(full_path)

        return jsonify({
            'message': 'Successfully deleted',
            'path': relative_path
        }), 200
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403
    except OSError as e:
        return jsonify({'error': f'Failed to delete: {str(e)}'}), 500


@app.route('/api/files/search', methods=['GET'])
def search_files():
    """
    Search for files/directories by name pattern.
    Query params:
        - user_id: the user identifier
        - query: search string
        - path: starting directory (default: root)
    """
    user_id = request.args.get('user_id')
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400

    query = request.args.get('query', '')
    if not query:
        return jsonify({'error': 'query is required'}), 400

    relative_path = request.args.get('path', '')
    user_root = get_user_root(user_id)
    search_root = resolve_safe_path(user_root, relative_path)

    if search_root is None:
        return jsonify({'error': 'Access denied: path is outside your root directory'}), 403

    if not os.path.exists(search_root) or not os.path.isdir(search_root):
        return jsonify({'error': 'Search path not found or is not a directory'}), 404

    results = []
    query_lower = query.lower()

    for dirpath, dirnames, filenames in os.walk(search_root):
        for name in dirnames + filenames:
            if query_lower in name.lower():
                entry_path = os.path.join(dirpath, name)
                info = get_file_info(entry_path, user_root)
                results.append(info)

        # Limit results
        if len(results) >= 100:
            break

    return jsonify({
        'query': query,
        'search_path': relative_path or '/',
        'total_results': len(results),
        'results': results
    }), 200


def _human_readable_size(size_bytes):
    """Convert bytes to human-readable format."""
    if size_bytes == 0:
        return "0 B"
    units = ['B', 'KB', 'MB', 'GB', 'TB']
    i = 0
    size = float(size_bytes)
    while size >= 1024 and i < len(units) - 1:
        size /= 1024
        i += 1
    return f"{size:.2f} {units[i]}"


